package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParse_withValidReader_returnsCSVParser() throws IOException {
        Reader reader = mock(Reader.class);
        CSVParser parser = csvFormat.parse(reader);
        assertNotNull(parser);
        // Verify CSVParser is constructed with the correct Reader and CSVFormat
        assertEquals(csvFormat, parser.getFormat());
        assertEquals(reader, parser.getReader());
    }

    @Test
    void testParse_withNullReader_throwsNullPointerException() {
        assertThrows(NullPointerException.class, () -> {
            csvFormat.parse(null);
        });
    }

    @Test
    void testParse_reflectionInvocation() throws Exception {
        Reader reader = mock(Reader.class);
        Method parseMethod = CSVFormat.class.getDeclaredMethod("parse", Reader.class);
        parseMethod.setAccessible(true);
        Object result = parseMethod.invoke(csvFormat, reader);
        assertNotNull(result);
        assertTrue(result instanceof CSVParser);
        CSVParser parser = (CSVParser) result;
        assertEquals(csvFormat, parser.getFormat());
        assertEquals(reader, parser.getReader());
    }

}
